import requests

def handle_eden(data_stream):
    for chunk in data_stream:
        if chunk:
            try:
                decoded_chunk = chunk.decode('utf-8')
                print(decoded_chunk, end='')
            except UnicodeDecodeError:
                print(f"Binary data received: {chunk}")
            except Exception as e:
                print(f"Error processing chunk: {e}")

if __name__ == "__main__":
    try:
        response = requests.get('https://httpbin.org/stream/5', stream=True, timeout=10)
        response.raise_for_status()

        handle_eden(response.iter_content(chunk_size=1024))

    except requests.exceptions.RequestException as e:
        print(f"Request error: {e}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
